// // This module compares a stored 4-bit value with an incoming 4-bit value. It features a register that holds the value to be compared and is updated when a read disable signal is asserted. The circuit outputs a success signal when the current read value does not match the stored value, and a fail signal when they do match. The stored value can be reset to one by asserting a reset signal.
module top_module(clock, reset, write_value, read_value, 
	read_value_reg_en, led_success, led_fail);input clock, reset, read_value_reg_en;
	input [3:0] write_value, read_value;
	output led_success, led_fail;


	reg [3:0] read_value_reg;

	assign led_success = (write_value == read_value_reg);
	assign led_fail = ~led_success;


	always @( posedge clock or posedge reset)
		begin
			if(reset)
				begin
					read_value_reg <= 4'b0;
				end
			else if (read_value_reg_en)
				begin
					read_value_reg <= read_value;
				end
		end

endmodule
